#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child process
 printf("Child (PID: %d) running...\n", getpid());
 sleep(2);
 printf("Child exiting with status 42\n");
 exit(42); // Exit with status 42
 } else {
 // Parent process
 int status;
 printf("Parent waiting for child (PID: %d)\n", pid);
 pid_t child_pid = wait(&status);

 if (child_pid > 0) {
 if (WIFEXITED(status)) {
 printf("Child %d exited normally with status: %d\n",
 child_pid, WEXITSTATUS(status));
 } else {
 printf("Child was killed by signal %d\n", WTERMSIG(status));
 }
 }
 }
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child process - simulate long work
 printf("Child working...\n");
 sleep(5);
 exit(0);
 } else {
 // Parent - do other work while checking child
 int status;
 pid_t result;

 while ((result = waitpid(pid, &status, WNOHANG)) == 0) {
 printf("Parent: Child still running, doing other work...\n");
 sleep(1); // Do some other work
 }

 if (result > 0) {
 printf("Child finished! Status: %d\n", WEXITSTATUS(status));
 } else if (result == -1) {
 perror("waitpid error");
 }
 }
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>
#include <sys/resource.h>

int main() {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child - do some CPU intensive work
 long sum = 0;
 for (int i = 0; i < 1000000; i++) {
 sum += i;
 }
 printf("Child computed: %ld\n", sum);
 exit(0);
 } else {
 // Parent - wait for child and get resource usage
 int status;
 struct rusage usage;

 pid_t result = wait4(pid, &status, 0, &usage);

 if (result > 0) {
 printf("Child PID: %d\n", result);
 printf("User CPU time: %ld.%06ld sec\n",
 usage.ru_utime.tv_sec, usage.ru_utime.tv_usec);
 printf("System CPU time: %ld.%06ld sec\n",
 usage.ru_stime.tv_sec, usage.ru_stime.tv_usec);
 printf("Max resident set size: %ld KB\n", usage.ru_maxrss);

 if (WIFEXITED(status)) {
 printf("Exit status: %d\n", WEXITSTATUS(status));
 }
 }
 }
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 int num_children = 3;
 pid_t pids[num_children];

 // Create multiple child processes
 for (int i = 0; i < num_children; i++) {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Each child does different work and exits with different status
 printf("Child %d (PID: %d) starting work...\n", i, getpid());
 sleep(i + 1); // Different sleep times
 int exit_status = (i + 1) * 10;
 printf("Child %d exiting with status %d\n", i, exit_status);
 exit(exit_status);
 } else {
 pids[i] = pid; // Store child PID
 }
 }

 // Parent waits for all children using waitpid with WNOHANG
 int remaining = num_children;
 int status;

 while (remaining > 0) {
 pid_t child = waitpid(-1, &status, WNOHANG);

 if (child > 0) {
 remaining--;
 if (WIFEXITED(status)) {
 printf("Parent: Child %d exited with status %d\n",
 child, WEXITSTATUS(status));
 } else {
 printf("Parent: Child %d killed by signal %d\n",
 child, WTERMSIG(status));
 }
 } else if (child == 0) {
 // No child has exited yet, do parent work
 printf("Parent doing other work...\n");
 sleep(1);
 } else {
 // Error
 perror("waitpid error");
 break;
 }
 }

 printf("All children collected. Parent exiting.\n");
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>
#include <signal.h>

void sigchld_handler(int sig) {
 int status;
 pid_t pid;

 // Reap all terminated children
 while ((pid = waitpid(-1, &status, WNOHANG)) > 0) {
 if (WIFEXITED(status)) {
 printf("Handler: Child %d exited with status %d\n",
 pid, WEXITSTATUS(status));
 }
 }
}

int main() {
 // Install signal handler for SIGCHLD
 struct sigaction sa;
 sa.sa_handler = sigchld_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = SA_RESTART | SA_NOCLDSTOP;

 if (sigaction(SIGCHLD, &sa, NULL) == -1) {
 perror("sigaction");
 exit(1);
 }

 // Fork some children
 for (int i = 0; i < 3; i++) {
 pid_t pid = fork();

 if (pid == 0) {
 // Child
 sleep(1);
 printf("Child %d exiting\n", getpid());
 exit(i);
 }
 }

 // Parent continues with other work
 // Children will be reaped by signal handler
 for (int i = 0; i < 5; i++) {
 printf("Parent doing work %d\n", i);
 sleep(1);
 }

 printf("Parent exiting\n");
 return 0;
}
